import torch
import torch_npu
import custom_ops_lib

_FN = 'ca6k_05320_custom'

class ModelNew(torch.nn.Module):
    def __init__(self, *init_inputs):
        super(ModelNew, self).__init__()
        # init_inputs: in_channels, out_channels, kernel_size, stride, padding, dilation
        self.in_channels = init_inputs[0]
        self.out_channels = init_inputs[1]
        self.kernel_size = init_inputs[2]  # tuple (D, H, W)
        self.stride = init_inputs[3]
        self.padding = init_inputs[4]
        self.dilation = init_inputs[5]
        # weight and bias will be created in forward (as in LazyConv3d)
        self.weight = None
        self.bias = None

    def forward(self, *inputs):
        x = inputs[0]
        # lazy initialization: first call creates weight and bias
        if self.weight is None:
            # infer in_channels from x
            in_channels = x.shape[1]
            # weight shape: (out_channels, in_channels, *kernel_size)
            weight = torch.randn(self.out_channels, in_channels, *self.kernel_size, device=x.device)
            self.weight = torch.nn.Parameter(weight)
            self.bias = torch.nn.Parameter(torch.zeros(self.out_channels, device=x.device))
        fn = getattr(custom_ops_lib, _FN)
        return fn(x, self.weight, self.bias, self.stride, self.padding, self.dilation)
